/**
 * Simple pixel-based scroll position manager.
 * Saves scrollTop and restores it after navigation.
 */
var STORAGE_KEY = 'react-hn-scroll'

/**
 * Save the current scroll position.
 * @param {string} routeKey - The route identifier (e.g., 'news', 'newest')
 */
function savePosition(routeKey) {
  var scrollTop = window.pageYOffset || document.documentElement.scrollTop || document.body.scrollTop || 0
  try {
    window.sessionStorage.setItem(STORAGE_KEY + ':' + routeKey, JSON.stringify({
      scrollTop: scrollTop,
      timestamp: Date.now()
    }))
  } catch (e) {
    // sessionStorage may be full or unavailable
  }
}

/**
 * Restore scroll position and highlight the first visible item.
 * @param {string} routeKey - The route identifier
 * @param {Object} options - Options
 * @param {number} options.highlightDuration - Highlight duration in ms (default 2500)
 * @returns {Function} cancel function
 */
function restorePosition(routeKey, options) {
  var opts = options || {}
  var highlightDuration = opts.highlightDuration !== undefined ? opts.highlightDuration : 2500

  var cancelled = false
  var highlightTimer = null

  function cancel() {
    cancelled = true
    if (highlightTimer) {
      clearTimeout(highlightTimer)
      highlightTimer = null
    }
  }

  var raw
  try {
    raw = window.sessionStorage.getItem(STORAGE_KEY + ':' + routeKey)
  } catch (e) {
    return cancel
  }

  if (!raw) return cancel

  var saved
  try {
    saved = JSON.parse(raw)
  } catch (e) {
    return cancel
  }

  if (!saved || !saved.scrollTop) return cancel

  // Clear saved position immediately so a page refresh doesn't replay it
  clearPosition(routeKey)

  // Wait for one paint so React items are in the DOM
  requestAnimationFrame(function() {
    if (cancelled) return

    // Restore scroll position
    var targetY = saved.scrollTop
    window.scrollTo(0, targetY)
    document.documentElement.scrollTop = targetY
    document.body.scrollTop = targetY

    // Highlight the item now at the top of the viewport
    var items = document.querySelectorAll('.ListItem[data-id]')
    for (var i = 0; i < items.length; i++) {
      var rect = items[i].getBoundingClientRect()
      if (rect.top >= -4 && rect.top < window.innerHeight / 2) {
        items[i].classList.add('ListItem--scroll-restore')
        highlightTimer = setTimeout(function(el) {
          return function() {
            if (!cancelled) {
              el.classList.remove('ListItem--scroll-restore')
            }
          }
        }(items[i]), highlightDuration)
        break
      }
    }
  })

  return cancel
}

/**
 * Clear saved position for a route.
 * @param {string} routeKey
 */
function clearPosition(routeKey) {
  try {
    window.sessionStorage.removeItem(STORAGE_KEY + ':' + routeKey)
  } catch (e) {
    // ignore
  }
}

export default {
  savePosition,
  restorePosition,
  clearPosition
}
